const toList = (value) => String(value || '')
  .split(/\r?\n|,/)
  .map((v) => v.trim())
  .filter(Boolean);

const unique = (values) => [...new Set(values)];
const clues = [];
const pushClues = (type, values) => {
  for (const value of unique(values)) clues.push({ type, value });
};

const ipAddressList = unique(toList($json.ipAddress));
const domainList = unique(toList($json.domain));
const indicatorList = unique(toList($json.indicator));
const malwareList = unique(toList($json.malware));
const vulnerabilityList = unique(toList($json.vulnerability).map((v) => v.toUpperCase()));
const victimList = unique(toList($json.victim));

pushClues('IPAddress', ipAddressList);
pushClues('Domain', domainList);
pushClues('Indicator', indicatorList);
pushClues('Malware', malwareList);
pushClues('Vulnerability', vulnerabilityList);
pushClues('Victim', victimList);

const clueSummary = clues.length
  ? clues.map((c) => `${c.type}: ${c.value}`).join(' | ')
  : '입력된 단서 없음';

return [{
  json: {
    ...$json,
    ipAddressList,
    domainList,
    indicatorList,
    malwareList,
    vulnerabilityList,
    victimList,
    clues,
    clueCount: clues.length,
    clueSummary,
  }
}];

const esc = (s) => String(s || '').replace(/\\/g, '\\\\').replace(/'/g, "\\'");
const blocks = [];
const add = (query) => blocks.push(query.trim());

for (const value of ($json.ipAddressList || [])) {
  const v = esc(value);
  add(`MATCH (ip:IPAddress {ip:'${v}'})<-[:HOSTED_ON]-(ind:Indicator)<-[:INVOLVES_INDICATOR]-(inc:Incident)-[:ATTRIBUTED_TO]->(ta:ThreatActor)
RETURN ta.name AS actor, 'IPAddress' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, ind.value AS shared_clue, inc.incident_id AS incident_id,
       'IP -> Indicator -> Incident -> ThreatActor' AS reasoning_path`);
  add(`MATCH (ip:IPAddress {ip:'${v}'})<-[:HOSTED_ON]-(ind:Indicator)-[:INDICATES]->(m:Malware)<-[:USES_MALWARE]-(ta:ThreatActor)
RETURN ta.name AS actor, 'IPAddress' AS clue_type, '${v}' AS clue_value, 2 AS dist,
       '${v}' AS input_hit, m.name AS shared_clue, '' AS incident_id,
       'IP -> Indicator -> Malware -> ThreatActor' AS reasoning_path`);
}

for (const value of ($json.domainList || [])) {
  const v = esc(value);
  add(`MATCH (d:Domain {domain:'${v}'})<-[:HOSTED_ON]-(ind:Indicator)<-[:INVOLVES_INDICATOR]-(inc:Incident)-[:ATTRIBUTED_TO]->(ta:ThreatActor)
RETURN ta.name AS actor, 'Domain' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, ind.value AS shared_clue, inc.incident_id AS incident_id,
       'Domain -> Indicator -> Incident -> ThreatActor' AS reasoning_path`);
  add(`MATCH (d:Domain {domain:'${v}'})<-[:HOSTED_ON]-(ind:Indicator)-[:INDICATES]->(m:Malware)<-[:USES_MALWARE]-(ta:ThreatActor)
RETURN ta.name AS actor, 'Domain' AS clue_type, '${v}' AS clue_value, 2 AS dist,
       '${v}' AS input_hit, m.name AS shared_clue, '' AS incident_id,
       'Domain -> Indicator -> Malware -> ThreatActor' AS reasoning_path`);
}

for (const value of ($json.indicatorList || [])) {
  const v = esc(value);
  add(`MATCH (ind:Indicator)
WHERE toLower(ind.value) = toLower('${v}') OR toLower(ind.value) CONTAINS toLower('${v}')
MATCH (inc:Incident)-[:INVOLVES_INDICATOR]->(ind)-[:HOSTED_ON]->(host)
MATCH (inc)-[:ATTRIBUTED_TO]->(ta:ThreatActor)
RETURN ta.name AS actor, 'Indicator' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, coalesce(host.ip, host.domain, ind.value) AS shared_clue, inc.incident_id AS incident_id,
       'Indicator -> Incident -> ThreatActor' AS reasoning_path`);
  add(`MATCH (ind:Indicator)
WHERE toLower(ind.value) = toLower('${v}') OR toLower(ind.value) CONTAINS toLower('${v}')
MATCH (ind)-[:INDICATES]->(m:Malware)<-[:USES_MALWARE]-(ta:ThreatActor)
RETURN ta.name AS actor, 'Indicator' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, m.name AS shared_clue, '' AS incident_id,
       'Indicator -> Malware -> ThreatActor' AS reasoning_path`);
  add(`MATCH (ind:Indicator)
WHERE toLower(ind.value) = toLower('${v}') OR toLower(ind.value) CONTAINS toLower('${v}')
MATCH (ind)-[:EXPLOITS]->(vul:Vulnerability)<-[:EXPLOITED]-(inc:Incident)-[:ATTRIBUTED_TO]->(ta:ThreatActor)
RETURN ta.name AS actor, 'Indicator' AS clue_type, '${v}' AS clue_value, 2 AS dist,
       '${v}' AS input_hit, vul.cve_id AS shared_clue, inc.incident_id AS incident_id,
       'Indicator -> Vulnerability -> Incident -> ThreatActor' AS reasoning_path`);
}

for (const value of ($json.malwareList || [])) {
  const v = esc(value);
  add(`MATCH (m:Malware)
WHERE toLower(m.name) = toLower('${v}') OR toLower(m.name) CONTAINS toLower('${v}')
MATCH (inc:Incident)-[:INVOLVES_MALWARE]->(m)
MATCH (inc)-[:ATTRIBUTED_TO]->(ta:ThreatActor)
RETURN ta.name AS actor, 'Malware' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, m.name AS shared_clue, inc.incident_id AS incident_id,
       'Malware -> Incident -> ThreatActor' AS reasoning_path`);
  add(`MATCH (ta:ThreatActor)-[:USES_MALWARE]->(m:Malware)
WHERE toLower(m.name) = toLower('${v}') OR toLower(m.name) CONTAINS toLower('${v}')
RETURN ta.name AS actor, 'Malware' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, m.name AS shared_clue, '' AS incident_id,
       'Malware -> ThreatActor' AS reasoning_path`);
}

for (const value of ($json.vulnerabilityList || [])) {
  const v = esc(value);
  add(`MATCH (vul:Vulnerability {cve_id:'${v}'})<-[:EXPLOITED]-(inc:Incident)-[:ATTRIBUTED_TO]->(ta:ThreatActor)
RETURN ta.name AS actor, 'Vulnerability' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, vul.cve_id AS shared_clue, inc.incident_id AS incident_id,
       'Vulnerability -> Incident -> ThreatActor' AS reasoning_path`);
  add(`MATCH (vul:Vulnerability {cve_id:'${v}'})<-[:EXPLOITS]-(ind:Indicator)-[:INDICATES]->(m:Malware)<-[:USES_MALWARE]-(ta:ThreatActor)
RETURN ta.name AS actor, 'Vulnerability' AS clue_type, '${v}' AS clue_value, 2 AS dist,
       '${v}' AS input_hit, m.name AS shared_clue, '' AS incident_id,
       'Vulnerability -> Indicator -> Malware -> ThreatActor' AS reasoning_path`);
}

for (const value of ($json.victimList || [])) {
  const v = esc(value);
  add(`MATCH (vic:Victim) WHERE toLower(vic.org_name) = toLower('${v}') OR toLower(vic.org_name) CONTAINS toLower('${v}')
MATCH (inc:Incident)-[:TARGETED]->(vic)
MATCH (inc)-[:ATTRIBUTED_TO]->(ta:ThreatActor)
RETURN ta.name AS actor, 'Victim' AS clue_type, '${v}' AS clue_value, 1 AS dist,
       '${v}' AS input_hit, vic.org_name AS shared_clue, inc.incident_id AS incident_id,
       'Victim -> Incident -> ThreatActor' AS reasoning_path`);
}

const fallback = "RETURN '' AS actor, '' AS clue_type, '' AS clue_value, 99 AS dist, '' AS input_hit, '' AS shared_clue, '' AS incident_id, 'No match' AS reasoning_path";
return [{ json: { ...$json, query: blocks.length ? blocks.join('\nUNION ALL\n') : fallback } }];

const input = $json || {};
const data = Array.isArray(input.data) ? input.data : [];

// 1) 첫 번째 객체는 request/context
const request = data[0] || {};

// 2) data[1]부터가 실제 Cypher row들인 구조 처리
let rows = [];

if (data.length > 1 && data[1]?.actor) {
  rows = data.slice(1);
} else {
  const response = data[1] || input.response || input.result || {};

  if (Array.isArray(response)) rows = response;
  else if (Array.isArray(response.data)) rows = response.data;
  else if (Array.isArray(response.results)) rows = response.results;
  else if (Array.isArray(response.records)) rows = response.records;
  else if (Array.isArray(response.rows)) rows = response.rows;
}

// 3) 혹시 read-cypher 결과가 { json: { ... } } 형태로 감싸진 경우 보정
rows = rows.map((row) => row.json || row).filter(Boolean);

// 4) actor가 있는 row만 사용
rows = rows.filter((row) => String(row.actor || '').trim());

const grouped = new Map();

for (const row of rows) {
  const actor = String(row.actor || '').trim();
  if (!actor) continue;

  if (!grouped.has(actor)) {
    grouped.set(actor, {
      actor,
      minDist: 999,
      inputHits: new Set(),
      sharedClues: new Set(),
      incidents: new Set(),
      reasoningPaths: [],
      clueTypes: new Set(),
    });
  }

  const entry = grouped.get(actor);

  entry.minDist = Math.min(entry.minDist, Number(row.dist || 99));

  if (row.input_hit) entry.inputHits.add(String(row.input_hit));
  if (row.shared_clue) entry.sharedClues.add(String(row.shared_clue));
  if (row.incident_id) entry.incidents.add(String(row.incident_id));

  if (row.reasoning_path && entry.reasoningPaths.length < 8) {
    entry.reasoningPaths.push(String(row.reasoning_path));
  }

  if (row.clue_type) entry.clueTypes.add(String(row.clue_type));
}

const clueCount = Number(request.clueCount || request.clues?.length || 0);

const allFindings = [...grouped.values()].map((entry) => {
  const proximityScore = 1 / (1 + entry.minDist);
  const breadthScore = clueCount > 0 ? entry.inputHits.size / clueCount : 0;
  const overlapScore = Math.min(1, entry.sharedClues.size / 10);

  let finalScore =
    proximityScore * 0.2 +
    breadthScore * 0.6 +
    overlapScore * 0.2;

  if (entry.incidents.size > 0) finalScore *= 1.15;

  const percent = Math.min(Math.round(finalScore * 1000) / 10, 100);

  return {
    actor: entry.actor,
    score: Math.round(finalScore * 1000) / 1000,
    percent,
    matchedClueCount: entry.inputHits.size,
    inputHits: [...entry.inputHits],
    sharedClues: [...entry.sharedClues].slice(0, 10),
    incidents: [...entry.incidents].slice(0, 8),
    reasoningPaths: [...new Set(entry.reasoningPaths)].slice(0, 6),
    clueTypes: [...entry.clueTypes],
    minDist: entry.minDist,
  };
}).sort((a, b) => b.score - a.score).slice(0, 15);

const toConfidence = (percent) => {
  if (percent >= 70) return '높음';
  if (percent >= 40) return '보통';
  if (percent > 0) return '낮음';
  return '판단 불가';
};

for (const finding of allFindings) {
  finding.confidence = toConfidence(finding.percent);
}

const topActors = allFindings.slice(0, 5);
const top = topActors[0] || null;

const evidenceSummaryForAi = topActors.map((f) => ({
  ThreatActor: f.actor,
  Confidence: `${f.percent}%`,
  MatchedArtifacts: f.inputHits,
  SharedClues: f.sharedClues,
  ReasoningPaths: f.reasoningPaths,
  IncidentLinks: f.incidents,
}));

const llmPrompt = [
  '[Task]',
  '제공된 단서와 지식 그래프 분석 결과를 토대로 위협 인텔리전스 보고서를 작성하세요.',
  '',
  '[Context]',
  `입력된 단서: ${request.clueSummary || '없음'}`,
  `전체 단서 수: ${clueCount}`,
  '',
  '[Matched Entities]',
  JSON.stringify(evidenceSummaryForAi, null, 2),
  '',
  '[Requirements]',
  '1. 한국어로 작성',
  '2. HTML fragment만 반환',
  '3. <section>, <h2>, <h3>, <p>, <ul>, <li>, <strong>, <code>만 사용',
  '4. 가장 가능성이 높은 Threat Actor와 이유를 결론 우선으로 작성',
  '5. Confidence 수치와 MatchedArtifacts, SharedClues, ReasoningPaths를 직접 인용',
  '6. 근거가 약한 경우 불확실성과 추가 확보가 필요한 단서를 명시',
].join('\n');

return [{
  json: {
    llmPrompt: llmPrompt,
    clueSummary: request.clueSummary,
    clueCount,
    clues: request.clues,
    schema: request.schema,
    cypherQuery: request.query || request.cypherQuery,
    rawRows: rows,
    topActors,
    topConfidence: top ? top.confidence : '판단 불가',
    evidenceSummaryForAi,

    // 문자열 버전 추가
    cluesText: JSON.stringify(request.clues, null, 2),
    schemaText: typeof request.schema === 'string'
      ? request.schema
      : JSON.stringify(request.schema, null, 2),

    rawRowsText: JSON.stringify(rows.slice(0, 200), null, 2),
    topActorsText: JSON.stringify(topActors, null, 2),
    evidenceSummaryText: JSON.stringify(evidenceSummaryForAi, null, 2),
  }
}];

const ranked = $json.data[0] || {};
const reportNode = $json.data[1] || {};
const aiHtml = String(reportNode.output || reportNode.text || '').trim();

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;')
  .replace(/'/g, '&#39;');

const topActors = ranked.topActors || [];
const top = topActors[0] || null;

const baseTextStyle = `
  box-sizing:border-box;
  max-width:100%;
  min-width:0;
  overflow-wrap:anywhere;
  word-break:break-word;
`;

const pageStyle = `
  font-family:Arial,sans-serif;
  width:100%;
  max-width:100%;
  margin:0;
  padding:32px;
  background:#f1f5f9;
  color:#0f172a;
  line-height:1.65;
  box-sizing:border-box;
  overflow-x:hidden;
  overflow-wrap:anywhere;
  word-break:break-word;
`;

const containerStyle = `
  width:100%;
  max-width:1280px;
  margin:0 auto;
  box-sizing:border-box;
  min-width:0;
`;

const cardStyle = `
  ${baseTextStyle}
  border:1px solid #dbe4f0;
  border-radius:24px;
  background:#ffffff;
  padding:28px;
  box-shadow:0 10px 30px rgba(15,23,42,0.06);
`;

const miniCardStyle = `
  ${baseTextStyle}
  padding:18px;
  border-radius:18px;
  background:#f8fafc;
  border:1px solid #e2e8f0;
`;

const codeStyle = `
  display:inline-block;
  max-width:100%;
  white-space:normal;
  overflow-wrap:anywhere;
  word-break:break-word;
  background:#e2e8f0;
  color:#0f172a;
  padding:2px 6px;
  border-radius:6px;
  margin:2px;
  font-size:12px;
`;

const clueBadges = (ranked.clues || []).map((clue) => `
  <span style="
    display:inline-flex;
    align-items:center;
    max-width:100%;
    padding:6px 10px;
    border-radius:999px;
    background:#e2e8f0;
    color:#0f172a;
    font-size:12px;
    font-weight:600;
    overflow-wrap:anywhere;
    word-break:break-word;
    box-sizing:border-box;
  ">
    ${escapeHtml(clue.type)}: ${escapeHtml(clue.value)}
  </span>
`).join('');

const rankingHtml = topActors.length ? topActors.map((actor, index) => {
  const incidents = actor.incidents?.length
    ? actor.incidents.map((v) => `<code style="${codeStyle}">${escapeHtml(v)}</code>`).join(' ')
    : '없음';

  const matched = actor.inputHits?.length
    ? actor.inputHits.map((v) => `<li>${escapeHtml(v)}</li>`).join('')
    : '<li>직접 일치 없음</li>';

  const shared = actor.sharedClues?.length
    ? actor.sharedClues.map((v) => `<li>${escapeHtml(v)}</li>`).join('')
    : '<li>공유 중간 단서 없음</li>';

  const paths = actor.reasoningPaths?.length
    ? actor.reasoningPaths.map((v) => `<li>${escapeHtml(v)}</li>`).join('')
    : '<li>경로 정보 없음</li>';

  return `
  <article style="${cardStyle}">
    <div style="display:flex;justify-content:space-between;gap:16px;align-items:flex-start;flex-wrap:wrap;min-width:0;">
      <div style="${baseTextStyle}">
        <p style="margin:0 0 8px 0;font-size:12px;letter-spacing:0.08em;text-transform:uppercase;color:#64748b;">
          Candidate ${index + 1}
        </p>
        <h3 style="margin:0;font-size:clamp(22px,3vw,28px);line-height:1.2;color:#0f172a;">
          ${escapeHtml(actor.actor)}
        </h3>
      </div>

      <div style="
        ${baseTextStyle}
        flex:1 1 220px;
        max-width:320px;
        padding:16px 18px;
        border-radius:18px;
        background:#eff6ff;
        border:1px solid #bfdbfe;
      ">
        <p style="margin:0 0 6px 0;"><strong>Confidence</strong> ${escapeHtml(actor.confidence)} (${actor.percent || 0}%)</p>
        <p style="margin:0 0 6px 0;"><strong>Score</strong> ${actor.score || 0}</p>
        <p style="margin:0;"><strong>Min Distance</strong> ${actor.minDist || '-'}</p>
      </div>
    </div>

    <div style="
      display:grid;
      grid-template-columns:repeat(auto-fit,minmax(260px,1fr));
      gap:16px;
      margin-top:20px;
      min-width:0;
      max-width:100%;
    ">
      <section style="${miniCardStyle}">
        <h4 style="margin:0 0 12px 0;color:#0f172a;">Matched Artifacts</h4>
        <ul style="margin:0;padding-left:18px;">${matched}</ul>
      </section>

      <section style="${miniCardStyle}">
        <h4 style="margin:0 0 12px 0;color:#0f172a;">Shared Clues</h4>
        <ul style="margin:0;padding-left:18px;">${shared}</ul>
      </section>

      <section style="${miniCardStyle}">
        <h4 style="margin:0 0 12px 0;color:#0f172a;">Related Incidents</h4>
        <p style="margin:0;">${incidents}</p>
      </section>
    </div>

    <section style="
      ${baseTextStyle}
      margin-top:18px;
      padding:18px;
      border-radius:18px;
      background:#fffdf7;
      border:1px solid #f5e7a1;
    ">
      <h4 style="margin:0 0 12px 0;color:#0f172a;">Reasoning Paths</h4>
      <ul style="margin:0;padding-left:18px;">${paths}</ul>
    </section>
  </article>`;
}).join('') : `
<section style="${cardStyle}">
  <h3 style="margin-top:0;">후보 없음</h3>
  <p style="margin-bottom:0;">입력 단서와 과거 지식그래프 사이에서 유의미한 Threat Actor 연결을 찾지 못했습니다.</p>
</section>`;

const executiveHtml = top ? `
<section style="
  ${baseTextStyle}
  padding:32px;
  border-radius:28px;
  background:linear-gradient(135deg,#0f172a,#1e3a8a);
  color:#f8fafc;
  box-shadow:0 18px 50px rgba(15,23,42,0.28);
">
  <p style="margin:0 0 12px 0;font-size:12px;letter-spacing:0.12em;text-transform:uppercase;color:#bfdbfe;">
    Executive Assessment
  </p>
  <h2 style="margin:0 0 12px 0;font-size:clamp(30px,5vw,42px);line-height:1.1;color:#ffffff;">
    ${escapeHtml(top.actor)}
  </h2>
  <p style="margin:0 0 8px 0;font-size:18px;">
    <strong>신뢰도</strong> ${escapeHtml(ranked.topConfidence || top.confidence)}
    / <strong>점수</strong> ${top.score || 0}
    / <strong>커버리지</strong> ${top.matchedClueCount || 0}개 단서
  </p>
  <p style="margin:0;font-size:15px;color:#dbeafe;">
    입력 단서와 과거 Incident, Malware, Vulnerability, Indicator 연결을 종합한 결과 가장 높은 상관성을 보인 후보입니다.
  </p>
</section>` : `
<section style="
  ${baseTextStyle}
  padding:32px;
  border-radius:28px;
  background:#111827;
  color:#f9fafb;
">
  <h2 style="margin:0 0 12px 0;">Threat Actor 추정 불가</h2>
  <p style="margin:0;">현재 저장된 과거 Incident/Indicator/Malware/Vulnerability 연결만으로는 우세한 후보를 도출하지 못했습니다.</p>
</section>`;

const analysisBlock = aiHtml || `
<section>
  <h2>분석 요약</h2>
  <p>LLM 분석 결과를 생성하지 못해 점수 기반 랭킹만 표시합니다.</p>
</section>`;

const queryBlock = `
<details style="
  ${baseTextStyle}
  margin-top:24px;
  border:1px solid #cbd5e1;
  border-radius:18px;
  background:#ffffff;
  padding:18px;
">
  <summary style="cursor:pointer;color:#1d4ed8;font-weight:700;">Used Cypher</summary>
  <pre style="
    white-space:pre-wrap;
    word-break:break-word;
    overflow-wrap:anywhere;
    background:#0f172a;
    color:#e2e8f0;
    padding:18px;
    border-radius:14px;
    overflow:auto;
    font-size:12px;
    line-height:1.6;
    max-width:100%;
    box-sizing:border-box;
  ">${escapeHtml(ranked.cypherQuery || '')}</pre>
</details>`;

const completionHtml = `
<div style="${pageStyle}">
  <div style="${containerStyle}">
    <header style="margin-bottom:28px;${baseTextStyle}">
      <p style="margin:0 0 10px 0;font-size:13px;letter-spacing:0.1em;text-transform:uppercase;color:#64748b;">
        Correlation Analysis Report
      </p>

      <h1 style="margin:0 0 12px 0;font-size:clamp(32px,6vw,52px);line-height:1.05;">
        Threat Actor Attribution
      </h1>

      <p style="margin:0 0 16px 0;font-size:16px;color:#475569;">
        입력된 사건 단서를 과거 지식그래프와 대조해 배후 Threat Actor 가능성을 평가한 결과입니다.
      </p>

      <div style="display:flex;flex-wrap:wrap;gap:10px;min-width:0;max-width:100%;">
        ${clueBadges || '<span style="font-size:14px;color:#64748b;">입력 단서 없음</span>'}
      </div>
    </header>

    ${executiveHtml}

    <section style="
      ${cardStyle}
      margin-top:28px;
    ">
      ${analysisBlock}
